@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

.root {
  margin: 2.5rem 0;
}

.header {
  height: 2rem;
  width: 12.5rem;
  /* shimmer from/to: var(--neutral-background-subtle); mid: #f0f0f0 (no semantic token maps to this lighter grey mid-stop) */
  background: linear-gradient(
    90deg,
    var(--neutral-background-subtle) 25%,
    #f0f0f0 50%,
    var(--neutral-background-subtle) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
  border-radius: 0.25rem;
  margin-bottom: 1.5rem;
}

.cards {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0.5rem;
}

@media (--md-up) {
  .cards {
    grid-template-columns: repeat(4, 1fr);
    gap: 1rem;
  }
}

.card {
  /* shimmer from/to: var(--neutral-background-subtle); mid: #fafafa (lighter stop, no exact semantic token) */
  background: linear-gradient(
    90deg,
    var(--neutral-background-subtle) 25%,
    #fafafa 50%,
    var(--neutral-background-subtle) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
  border-radius: 0.5rem;
  padding-top: 100%;
  position: relative;
}

.cardContent {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 1rem;
  /* white background for the text area — intentionally not a semantic token (it is a literal white overlay on the card) */
  background: white;
  border-radius: 0 0 0.5rem 0.5rem;
}

.cardTitle {
  height: 1rem;
  /* shimmer from/to: var(--neutral-background-subtle); mid: #f0f0f0 */
  background: linear-gradient(
    90deg,
    var(--neutral-background-subtle) 25%,
    #f0f0f0 50%,
    var(--neutral-background-subtle) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
  border-radius: 0.125rem;
  margin-bottom: 0.5rem;
}

.cardPrice {
  height: 0.875rem;
  width: 60%;
  /* shimmer from/to: var(--neutral-background-subtle); mid: #f0f0f0 */
  background: linear-gradient(
    90deg,
    var(--neutral-background-subtle) 25%,
    #f0f0f0 50%,
    var(--neutral-background-subtle) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
  border-radius: 0.125rem;
}

import React from 'react';
import styles from './LoadingSkeleton.module.css';

export type LoadingSkeletonProps = {
  /** Additional CSS class name(s) */
  className?: string;
  /** Inline style overrides */
  style?: React.CSSProperties;
};

/**
 * LoadingSkeleton — shimmer placeholder for the TrendingProductsWidget carousel.
 *
 * Renders a header placeholder and four card placeholders in a responsive grid.
 * Ported from the CarouselSkeleton in catalog's TrendingProducts feature.
 */
export const LoadingSkeleton = React.forwardRef<HTMLDivElement, LoadingSkeletonProps>(
  function LoadingSkeleton({ className, style }, ref) {
    const rootClass = [styles.root, className].filter(Boolean).join(' ');

    return (
      <div ref={ref} className={rootClass} style={style} data-testid="carousel-skeleton">
        <div className={styles.header} />
        <div className={styles.cards}>
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className={styles.card}>
              <div className={styles.cardContent}>
                <div className={styles.cardTitle} />
                <div className={styles.cardPrice} />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  },
);

LoadingSkeleton.displayName = 'LoadingSkeleton';
